const b = $input.first().json.body || $input.first().json;

const reviewer = b.reviewer_name || b.author || b.name || 'Cliente';
const rating = parseInt(b.rating || b.stars || 5);
const review_text = b.review || b.text || b.comment || b.body || '';
const barbershop_name = b.barbershop_name || 'la barbería';

const OPENAI = 'TU_OPENAI_API_KEY';

const stars = '⭐'.repeat(Math.max(1, Math.min(5, rating)));

return [{ json: { reviewer, rating, stars, review_text, barbershop_name, openai_key: OPENAI } }];

